@app.route("/items", methods=["POST"])
def create_item():
    payload = request.get_json(silent=True) or {}
    name = payload.get("name")
    value = payload.get("value")

    if not name or not value:
        return jsonify({"error": "Fields 'name' and 'value' are required"}), 400

    conn = get_db_connection()
    cur = conn.cursor()
    cur.execute("INSERT INTO items (name, value) VALUES (?, ?)", (name, value))
    conn.commit()
    item_id = cur.lastrowid
    conn.close()

    cache_delete(make_cache_key("db_query:all_items", {}))

    return jsonify({
        "message": "Item created",
        "id": item_id,
    }), 201

@app.route("/items/<int:item_id>", methods=["PUT"])
def update_item(item_id):
    payload = request.get_json(silent=True) or {}
    name = payload.get("name")
    value = payload.get("value")

    if not name or not value:
        return jsonify({"error": "Fields 'name' and 'value' are required"}), 400

    conn = get_db_connection()
    cur = conn.cursor()
    cur.execute("UPDATE items SET name = ?, value = ? WHERE id = ?", (name, value, item_id))
    updated = cur.rowcount
    conn.commit()
    conn.close()

    if updated == 0:
        return jsonify({"error": "Item not found"}), 404

    cache_delete(make_cache_key("db_query:item_by_id", {"item_id": item_id}))
    cache_delete(make_cache_key("db_query:all_items", {}))

    return jsonify({"message": "Item updated"})

